public static long[] solve(String[] words) {
    int n = words.length;
    long[] answer = new long[n];
    if (n == 1) {
        answer[0] = 0;
        return answer;
    }

    for (int i = 0; i < n; i++) {
        int maxLen = 0;
        for (int j = 0; j < n - 1; j++) {
            int currentJ = j < i ? j : j + 1;
            int nextJ = currentJ + 1;
            if (nextJ >= n) continue;
            String a = words[currentJ];
            String b = words[nextJ];
            int commonLen = 0;
            int minLen = Math.min(a.length(), b.length());
            while (commonLen < minLen && a.charAt(commonLen) == b.charAt(commonLen)) {
                commonLen++;
            }
            if (commonLen > maxLen) {
                maxLen = commonLen;
            }
        }
        answer[i] = maxLen;
    }
    return answer;
}
